/* Minimal local Bootstrap JS compatibility layer for TERRAit static/offline build. */
(function(){
  function q(el){return typeof el==='string'?document.querySelector(el):el;}
  class Modal{constructor(el){this.el=q(el);}show(){if(!this.el)return;this.el.classList.add('show');this.el.removeAttribute('aria-hidden');document.body.classList.add('modal-open');}hide(){if(!this.el)return;this.el.classList.remove('show');this.el.setAttribute('aria-hidden','true');document.body.classList.remove('modal-open');}static getOrCreateInstance(el){el=q(el);if(!el)return new Modal(null);if(!el.__modal)el.__modal=new Modal(el);return el.__modal;}}
  class Toast{constructor(el,opts){this.el=q(el);this.opts=Object.assign({delay:2200},opts||{});this.timer=null;}show(){if(!this.el)return;this.el.classList.add('show');clearTimeout(this.timer);this.timer=setTimeout(()=>this.hide(),this.opts.delay);}hide(){if(!this.el)return;this.el.classList.remove('show');}static getOrCreateInstance(el,opts){el=q(el);if(!el)return new Toast(null,opts);if(!el.__toast)el.__toast=new Toast(el,opts);return el.__toast;}}
  document.addEventListener('click',function(e){const close=e.target.closest('[data-bs-dismiss="modal"]');if(close){const modal=close.closest('.modal');if(modal)Modal.getOrCreateInstance(modal).hide();}const toastClose=e.target.closest('[data-bs-dismiss="toast"]');if(toastClose){const toast=toastClose.closest('.toast');if(toast)Toast.getOrCreateInstance(toast).hide();}});
  window.bootstrap={Modal,Toast};
})();
